head.script:
//-------------------------------------------------------------------------
// 전역변수
//-------------------------------------------------------------------------
scwin.ed_lodeptCd = "";
scwin.ed_input_textKor = "";
scwin.ed_wrkDt = "";

scwin.cmdKnd = "";

scwin.bCheck = "";
scwin.gClickFlag;
scwin.resultCnt = 0;
scwin.v_workClsCd = "";
scwin.gShiftComboCode = "";
scwin.sCurrDate = WebSquare.date.getCurrentServerDate();  // 서버를 기준으로 현재 날짜 반환
scwin.loUpperLobranCd = $c.data.getMemInfo("loUpperLobranCd"); // 회원 점소 데이터
scwin.loUpperLobranNm = $c.data.getMemInfo("loUpperLobranNm");
scwin.selectedRow = "";
scwin.selectedGrid = "";
scwin.selectedCol = "";
scwin.bOnPopUp = false;

scwin.gfixedArrangeYn = 0;//고정배치여부 

scwin.checkStaffArray = [];
scwin.colMoveCheck = 0;

//20.09.24 RPA용
//인천 기능직 실적 입력 시 복리후생비 발생 하지 않는 로직용
scwin.lobranCd = "";
scwin.pos_groupCode = 0;
scwin.olddata = "";

scwin.debugCheck = 0;
//-------------------------------------------------------------------------
// 화면 로딩시
//-------------------------------------------------------------------------
scwin.onpageload = async function () {
    const codeOptions = [
        // { grpCd: "OP160", compID: "acb_occptypeCd" }, // 셀렉트
        // { grpCd: "OP161", compID: "acb_dtlOccptypeCd" }, // 셀렉트
        { grpCd: "OP300", compID: "gr_workTime:commWrkScStd, gr_workTime:rainScStd, gr_workTime:snowScStd, gr_workTime:gangWrkStd, gr_workTime:odrReqStd, gr_workTime:extendWrkScStd, gr_workTime:holiWrkScStd  " }, // 셀렉트
    ];
    $c.data.setCommonCode(codeOptions, scwin.onLoadCommonCode);


    const param= [
        {
            compID: "acb_occptypeCd",
            method: "getCodeList",
            param1: "OP160",
            param2: 1,
            param3: "1",

            // outputFields를 정의하면, 이게 자동으로 param4: [1, 3]으로 변환되어 서버로 전송됩니다.
            outputFields: ["CD", "CD_NM"]
        },
        {
            compID: "acb_dtlOccptypeCd",
            method: "getCodeList",
            param1: "OP161",
            param2: 1,
            param3: "1",

            // outputFields를 정의하면, 이게 자동으로 param4: [1, 3]으로 변환되어 서버로 전송됩니다.
            outputFields: ["CD", "CD_NM"]
        }

    ];
    $c.data.setDsCommonUtil(param);



    //근무구분
    dma_retrieveCode.set("grpCd", "OP220");
    await $c.sbm.execute(sbm_workCls);

    //휴무사유 -> 정렬 요청 부분 있음
    await scwin.f_vacaRsnCd();

    //Shift
    dma_retrieveCode.set("grpCd", "OP117");
    await $c.sbm.execute(sbm_shift);

    //작업단계
    dma_retreiveWrkStp.set("upperCd", "99");
    await $c.sbm.execute(sbm_wkrStp);

    //업무내용
    dma_retrieveCode.set("grpCd", "OP221");
    await $c.sbm.execute(sbm_tskCntn);

    ica_qryWrkDt.setValue(scwin.sCurrDate);

    gr_workTime.setColumnVisible("cond2", false);
    gr_workTime.setColumnVisible("cond3", false);
    gr_workTime.setColumnVisible("cond4", false);
    gr_workTime.setColumnVisible("cond5", false);
    gr_workTime.setColumnVisible("cond6", false);
    gr_workTime.setColumnVisible("cond7", false);
    gr_workTime.setColumnVisible("cond8", false);

    gr_workTime.setColumnVisible("staffNo", false);
    gr_workTime.setColumnVisible("workDt", false);
    gr_workTime.setColumnVisible("workSeq", false);
    gr_workTime.setColumnVisible("shift", false);
    gr_workTime.setColumnVisible("emgcOdrYn", false);
    gr_workTime.setColumnVisible("commWrkScYn", false);
    gr_workTime.setColumnVisible("commWrkScStd", false);
    gr_workTime.setColumnVisible("rainScYn", false);
    gr_workTime.setColumnVisible("rainScStd", false);
    gr_workTime.setColumnVisible("snowScYn", false);
    gr_workTime.setColumnVisible("snowScStd", false);
    gr_workTime.setColumnVisible("gangWrkYn", false);
    gr_workTime.setColumnVisible("gangWrkStd", false);
    gr_workTime.setColumnVisible("odrReqYn", false);
    gr_workTime.setColumnVisible("odrReqStd", false);
    gr_workTime.setColumnVisible("extendWrkScYn", false);
    gr_workTime.setColumnVisible("extendWrkScStd", false);
    gr_workTime.setColumnVisible("holiWrkScYn", false);
    gr_workTime.setColumnVisible("holiWrkScStd", false);


    gr_workTime.setColumnReadOnly("emgcOdrYn", true);
    gr_workTime.setColumnReadOnly("commWrkScYn", true);
    gr_workTime.setColumnReadOnly("commWrkScStd", true);
    gr_workTime.setColumnReadOnly("rainScYn", true);
    gr_workTime.setColumnReadOnly("rainScStd", true);
    gr_workTime.setColumnReadOnly("snowScYn", true);
    gr_workTime.setColumnReadOnly("snowScStd", true);
    gr_workTime.setColumnReadOnly("gangWrkYn", true);
    gr_workTime.setColumnReadOnly("gangWrkStd", true);
    gr_workTime.setColumnReadOnly("odrReqYn", true);
    gr_workTime.setColumnReadOnly("odrReqStd", true);
    gr_workTime.setColumnReadOnly("extendWrkScYn", true);
    gr_workTime.setColumnReadOnly("extendWrkScStd", true);
    gr_workTime.setColumnReadOnly("holiWrkScYn", true);
    gr_workTime.setColumnReadOnly("holiWrkScStd", true);

    // let options = {
    //     type : "allColumn",
    //     minWidth : 1200
    // }

    // gr_workTime.setAutoFit(options)

};

scwin.onUdcCompleted = function () {
    ed_branCd.focus();
    ed_branCd.setValue(scwin.loUpperLobranCd);
    ed_branCd.options.hidVal = scwin.loUpperLobranCd;
    ed_branNm.setValue(scwin.loUpperLobranNm);
    ed_branNm.options.hidVal = scwin.loUpperLobranNm;

    scwin.ed_lodeptCd = ed_branCd.getValue();

    // 하단 그리드 북항 컬럼 노출여부
    if (ed_branCd.getValue() == "4AA") {
        gr_workTime.setColumnVisible("npGubun", true);
    } else {
        gr_workTime.setColumnVisible("npGubun", false);
    }
};

/**
 * method
 * @name onLoadCommonCode
 * @description 공통코드 조회 콜백
 */
scwin.onLoadCommonCode = function () {
    // acb_occptypeCd.addItem("전체", "", null, 0);
    // acb_occptypeCd.setValue("");
    // acb_dtlOccptypeCd.addItem("전체", "", null, 0);
    // acb_dtlOccptypeCd.setValue("");
};

//20.10.29 업무혁신추진팀 장원석주임 요청사항, 휴무사유 order by
scwin.f_vacaRsnCd = async function () {
    // SELECT 절 
    let param1 = " CD       as COL1" +
        ",CD_NM 	 as COL2" +
        ",SORT_SEQ as COL3 " +
        ",'' 		as COL4 " +
        ",'' 		as COL5 " +
        ",'' 		as COL6 " +
        ",''      as COL7 " +
        ",''      as COL8 " +
        ",''      as COL9 " +
        ",''      as COL10";

    dma_vacaRsn.setJSON({
        "sysCd": "CommonEBC",
        "queryId": "dinymicQueryTest",
        "param1": param1,
        "param2": " TB_ZZ002 ", // 대상테이블
        "param3": " AND GRP_CD = 'OP164' AND USE_YN = '1' ",   // 조건절
        "param4": "SORT_SEQ ASC",
    });

    await $c.sbm.execute(sbm_vacaRsn);
}

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.btn_retrieve_onClick = async function (e) {
    if (! await $c.gus.cfValidate([tb_searchCondition])) {
        return;
    }

    //Data, DataHeader Delete
    ds_staff.removeAll();

    //Only Data Delete
    ds_Present.removeAll();
    ds_workTime.removeAll();


    dma_searchStaff.set("branCd", ed_branCd.getValue()); //점소
    dma_searchStaff.set("lobranCd", ed_branCd.getValue()); //점소
    dma_searchStaff.set("occptypeCd", acb_occptypeCd.getValue());    //직종
    dma_searchStaff.set("dtlOccptypeCd", acb_dtlOccptypeCd.getValue()); //상세직종
    dma_searchStaff.set("staffNo", ed_staffNo.getValue()); //인원
    dma_searchStaff.set("wrkDt", ica_qryWrkDt.getValue()); //일자
    dma_searchStaff.set("vacaDt", "");

    scwin.ed_wrkDt = ica_qryWrkDt.getValue();

    scwin.cmdKnd = "retrieve";

    await $c.sbm.execute(sbm_searchStaff);

    await $c.sbm.execute(sbm_searchVacation);
};

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.btn_save_onClick = async function (e) {
    let j = 0;
    let z = 0;
    scwin.debugCheck++;
    if (ds_workTime.getTotalRow() == 0 && ds_Present.getTotalRow() == 0) {
        $c.win.alert($c.data.getMessage(MSG_CM_ERR_001, "실적과 기능직 휴무"));
        return;
    }
    if (ds_Present.getModifiedIndex().length == 0 && ds_workTime.getModifiedIndex().length == 0) {
        scwin.debugCheck++;
        //기능직 휴무 그리드에 수정사항이나 추가사항이 없다면,
        //인원을 선택했는지(ds_staff)  Check
        for (i = 0; i < ds_staff.getTotalRow(); i++) {
            if (ds_staff.getCellData(i, "checkBox") == "T") {
                j = j + 1;
                scwin.gfixedArrangeYn = ds_staff.getCellData(i, "fixedArrangeYn");
            }
        }

        if (j == 0) {
            $c.win.alert("인원을 선택 후 저장하십시오.");
            return;
        }

    } else {
        if (ds_Present.getTotalRow() > 0 || ds_Present.getModifiedIndex().length >= 1) {
            let stDt = "";
            let endDt = "";

            //기능직휴무 그리드(gr_vacation), 필수입력항목 null 체크
            if (! await $c.gus.cfValidate([gr_vacation])) {
                return;
            }

            for (z = 0; z < ds_Present.getTotalRow(); z++) {
                stDt = ds_Present.getCellData(z, "vacaStDt");
                endDt = ds_Present.getCellData(z, "vacaEndDt");

                // 휴무시작일자가 종료일자보다 이후일 경우
                if (!$c.gus.cfIsAfterDate(stDt, endDt, false)) {
                    $c.win.alert(MSG_CM_ERR_039);
                    return false;
                }
            }
            if (ds_Present.getModifiedIndex().length >= 1) {
                //저장하시겠습니까?
                if (await $c.win.confirm(MSG_CM_CRM_001)) {
                    await scwin.saveCheckedStaff();
                    scwin.pos_groupCode = gr_staff.getFocusedRowIndex();  // 저장 전의 위치 저장
                    // sbm_main.userData1="noError";
                    await $c.sbm.execute(sbm_saveVacation);
                }
            }
        }

        //근무시간 유무
        if (ds_workTime.getTotalRow() > 0) {
            for (i = 0; i < ds_staff.getTotalRow(); i++) {
                if (ds_staff.getCellData(i, "checkBox") == "T") {
                    j = j + 1;
                    scwin.gfixedArrangeYn = ds_staff.getCellData(i, "fixedArrangeYn");
                }
            }

            if (j == 0) {
                $c.win.alert("인원을 선택 후 저장하십시오.");
                return;
            }

            if (ds_workTime.getTotalRow() == 1 && ds_workTime.getCellData(0, "workClsCd") == "N") {
                $c.win.alert("근무구분을 업무간휴무만 입력하여 저장할 수 없습니다 .");
                return;
            }

            //근무구분별 필수항목 첵크(근무구분이 배치인 경우 작업지시번호,작업단계 필수) 
            for (i = 0; i < ds_workTime.getTotalRow(); i++) {
                if (ds_workTime.getCellData(i, "workClsCd") == "A" && scwin.gfixedArrangeYn != "1") {
                    if (ds_workTime.getCellData(i, "wrkIndictNo") == "") {
                        $c.win.alert("근무구분이 배치인 경우 작업지시번호는 필수입니다.");
                        gr_workTime.setFocusedCell(i, "wrkIndictNo")
                        return;
                    }

                    if (ds_workTime.getCellData(i, "wrkStpCd") == "") {
                        $c.win.alert("근무구분이 배치인 경우 작업단계는 필수입니다.");
                        gr_workTime.setFocusedCell(i, "wrkStpCd")
                        return;
                    }

                    if (ds_workTime.getCellData(i, "commWrkScYn") == "1" && ds_workTime.getCellData(i, "commWrkScStd") == 0) {
                        $c.win.alert("원당작업의 경우 적용시간이 필요합니다..");
                        gr_workTime.setFocusedCell(i, "commWrkScStd")
                        return;
                    }

                    if (ds_workTime.getCellData(i, "rainScYn") == "1" && ds_workTime.getCellData(i, "rainScStd") == 0) {
                        $c.win.alert("우천작업의 경우 적용시간이 필요합니다..");
                        gr_workTime.setFocusedCell(i, "rainScStd")
                        return;
                    }

                    if (ds_workTime.getCellData(i, "snowScYn") == "1" && ds_workTime.getCellData(i, "snowScStd") == 0) {
                        $c.win.alert("설천작업의 경우 적용시간이 필요합니다..");
                        gr_workTime.setFocusedCell(i, "snowScStd")
                        return;
                    }

                    if (ds_workTime.getCellData(i, "gangWrkYn") == "1" && ds_workTime.getCellData(i, "gangWrkStd") == 0) {
                        $c.win.alert("Gang작업의 경우 적용시간이 필요합니다..");
                        gr_workTime.setFocusedCell(i, "gangWrkStd")
                        return;
                    }

                    if (ds_workTime.getCellData(i, "odrReqYn") == "1" && ds_workTime.getCellData(i, "odrReqStd") == 0) {
                        $c.win.alert("오더작업의 경우 적용시간이 필요합니다..");
                        gr_workTime.setFocusedCell(i, "odrReqStd")
                        return;
                    }

                    if (ds_workTime.getCellData(i, "extendWrkScYn") == "1" && ds_workTime.getCellData(i, "extendWrkScStd") == 0) {
                        $c.win.alert("원당작업의 경우 적용시간이 필요합니다..");
                        gr_workTime.setFocusedCell(i, "extendWrkScStd")
                        return;
                    }

                    if (ds_workTime.getCellData(i, "holiWrkScYn") == "1" && ds_workTime.getCellData(i, "holiWrkScStd") == 0) {
                        $c.win.alert("명절작업의 경우 적용시간이 필요합니다..");
                        gr_workTime.setFocusedCell(i, "holiWrkScStd")
                        return;
                    }
                }
            }

            //작업시간 
            if (! await $c.gus.cfValidate([gr_workTime])) {
                return;
            }

            if (!scwin.f_checkVacationDate()) {
                return;
            }

            for (i = 0; i < ds_workTime.getTotalRow(); i++) {
                let workSt = ds_workTime.getCellData(i, "workStDt") + ds_workTime.getCellData(i, "workStHh")
                let workEnd = ds_workTime.getCellData(i, "workEndDt") + ds_workTime.getCellData(i, "workEndHh")

                let startDate = workSt.trim();
                let endDate = workEnd.trim();
                let totalDate = (endDate - startDate) / 1000 / 60 / 60;
                if (totalDate >= 24) {
                    $c.win.alert("작업일이 하루가 넘습니다.");
                }
            }

            if (ds_workTime.getModifiedIndex().length >= 1) {
                if (await $c.win.confirm(MSG_CM_CRM_001)) {
                    scwin.debugCheck++;
                    await scwin.saveCheckedStaff();

                    scwin.debugCheck++;
                    scwin.pos_groupCode = gr_staff.getFocusedRowIndex();  // 저장 전의 위치 저장
                    // sbm_saveWork.userData1="noError";
                    await $c.sbm.execute(sbm_saveWork);
                }
            }
        }
    }
};

scwin.saveCheckedStaff = async function () {
    scwin.debugCheck++;
    scwin.checkStaffArray = [];
    let checked = ds_staff.getMatchedIndex("checkBox", "T", true);
    for (let row of checked) {
        ds_staff.modifyRowStatus(row, "C");
        scwin.checkStaffArray.push(ds_staff.getCellData(row, "staffNo"));
    }
};

//-------------------------------------------------------------------------
// 작업시간 Validation
//-------------------------------------------------------------------------  
scwin.f_checkVacationDate = function () {
    let wrkDt = scwin.ed_wrkDt;
    let wrkStDt;
    let wrkStHh;
    let wrkStMm;
    let wrkEndDt;
    let wrkEndHh;
    let wrkEndMm;
    let wrkStDtm;
    let wrkEndDtm;

    for (i = 0; i < ds_workTime.getTotalRow(); i++) {
        wrkStDt = ds_workTime.getCellData(i, "workStDt");
        wrkStHh = ds_workTime.getCellData(i, "workStHh");
        wrkStMm = ds_workTime.getCellData(i, "workStHh").substring(2, 4);
        wrkEndDt = ds_workTime.getCellData(i, "workEndDt");
        wrkEndHh = ds_workTime.getCellData(i, "workEndHh");
        wrkEndMm = ds_workTime.getCellData(i, "workEndHh").substring(2, 4);
        wrkStDtm = wrkStDt + wrkStHh;
        wrkEndDtm = wrkEndDt + wrkEndHh;

        if (wrkStMm != "00" && wrkStMm != "30") {
            $c.win.alert((i+1) + "번째의 시간은 30분 단위로 입력 가능합니다.");
            gr_workTime.setFocusedCell(i, "workStHh")
            return false;
        }

        if (wrkEndMm != "00" && wrkEndMm != "30") {
            $c.win.alert((i+1) + "번째의 시간은 30분 단위로 입력 가능합니다.");
            gr_workTime.setFocusedCell(i, "workEndHh")
            return false;
        }

        if (Number(ds_workTime.getCellData(i, "workStHh").substr(0, 2)) > 23) {
            $c.win.alert($c.data.getMessage(MSG_CM_ERR_043, "시작시간")); // "유효하지 않는 @ 입니다.\n다시 입력하여주십시요"
            gr_workTime.setFocusedCell(i, "workEndHh")
            return;
        }

        if (Number(ds_workTime.getCellData(i, "workStHh").substr(2, 2)) > 59) {
            $c.win.alert($c.data.getMessage(MSG_CM_ERR_043, "시작시간")); // "유효하지 않는 @ 입니다.\n다시 입력하여주십시요"
            gr_workTime.setFocusedCell(i, "workStHh")
            return;
        }

        if (Number(ds_workTime.getCellData(i, "workEndHh").substr(0, 2)) > 24) {
            $c.win.alert($c.data.getMessage(MSG_CM_ERR_043, "종료시간")); // "유효하지 않는 @ 입니다.\n다시 입력하여주십시요"
            gr_workTime.setFocusedCell(i, "workEndHh")
            ds_workTime.setRowPosition(i);
            return;
        }
        if (ds_workTime.getCellData(i, "workEndHh").substr(0, 2) == "00" && ds_workTime.getCellData(i, "workEndHh").substr(2, 2) == "00") {
            $c.win.alert($c.data.getMessage(MSG_CM_ERR_043, "종료시간")); // "유효하지 않는 @ 입니다.\n다시 입력하여주십시요"
            gr_workTime.setFocusedCell(i, "workEndHh")
            return;
        }
        if (ds_workTime.getCellData(i, "workEndHh").substr(0, 2) == "24" && Number(ds_workTime.getCellData(i, "workEndHh").substr(2, 2)) > 00) {
            $c.win.alert($c.data.getMessage(MSG_CM_ERR_043, "종료시간")); // "유효하지 않는 @ 입니다.\n다시 입력하여주십시요"
            gr_workTime.setFocusedCell(i, "workEndHh")
            return;
        }
        if (Number(ds_workTime.getCellData(i, "workEndHh").substr(2, 2)) > 59) {
            $c.win.alert($c.data.getMessage(MSG_CM_ERR_043, "종료시간")); // "유효하지 않는 @ 입니다.\n다시 입력하여주십시요"
            gr_workTime.setFocusedCell(i, "workEndHh")
            return;
        }

        //입력한 작업시작일자가 조회일자이후인가
        if (wrkDt > wrkStDt) {
            $c.win.alert((i+1) + "번째의 근무시간 일자는 기준일자 + 1일까지 입력가능합니다.");
            gr_workTime.setFocusedCell(i, "workStDt")
            return false;
        }

        //입력한 작업시작일자가 하루를 초과하는가
        let diffDay = $c.date.diffDate(wrkDt, wrkStDt);

        if (diffDay > 1) {
            $c.win.alert((i+1) + "번째의 근무시간 일자는 기준일자 + 1일까지 입력가능합니다.");
            gr_workTime.setFocusedCell(i, "workStDt")
            return false;
        }

        //전일작업종료일자
        let yestWrkDtm;
        let yestWrkDt;
        let yestWrkHh;
        let staffNo;
        let staffNm;

        for (let k = 0; k < ds_staff.getTotalRow(); k++) {
            if (ds_staff.getCellData(k, "checkBox") == "T") {
                yestWrkDtm = ds_staff.getCellData(k, "yestWrkDt");
                yestWrkDt = ds_staff.getCellData(k, "yestWrkDt").substring(0, 8);
                yestWrkHh = ds_staff.getCellData(k, "yestWrkDt").substring(8, 4);
                staffNm = ds_staff.getCellData(k, "staffNm");

                //작업시작시간이 전일 작업종료일자 이후 인가
                if (yestWrkDt != "") {
                    if (Number(yestWrkDtm) > Number(wrkStDtm)) {
                        if (Number(yestWrkHh) > Number(wrkStHh)) {
                            $c.win.alert(staffNm + "의 작업시작시간이 전일 작업종료시간 이전입니다.")
                            gr_workTime.setFocusedCell(i, "workStHh")
                            return false;
                        }
                    }
                }
            }
        }

        //작업시작일자가 작업종료일자 이후 인가
        if (wrkStDt > wrkEndDt) {
            $c.win.alert((i+1) + "번째의 작업시작일시는 작업종료일시 이전이어야 합니다.");
            gr_workTime.setFocusedCell(i, "workStDt")
            return false;
            break;
        }

        if (wrkStDtm > wrkEndDtm) {
            $c.win.alert((i+1) + "번째의 작업시작일시는 작업종료일시 이전이어야 합니다.");
            gr_workTime.setFocusedCell(i, "workStHh")
            return false;
            break;
        }

        diffDay = $c.date.diffDate(wrkDt, wrkEndDt);
        if (diffDay > 1) {
            $c.win.alert((i+1) + "번째의 근무시간 일자는 기준일자 + 1일까지 입력가능합니다.");
            gr_workTime.setFocusedCell(i, "workEndDt")
            return false;
        }

    }

    let sStDt = "";
    let sEndDt = "";
    let tStDt = "";
    let tEndDt = "";
    let cnt = 0;
    for (i = 0; i < ds_workTime.getTotalRow(); i++) {
        if (ds_workTime.getRowStatus(i) != "D") {
            sStDt = ds_workTime.getCellData(i, "workStDt") + ds_workTime.getCellData(i, "workStHh");
            sEndDt = ds_workTime.getCellData(i, "workEndDt") + ds_workTime.getCellData(i, "workEndHh");

            for (j = i + 1; j <= ds_workTime.getTotalRow(); j++) {
                if (ds_workTime.getRowStatus(j) != "D") {
                    cnt = 0;
                    tStDt = ds_workTime.getCellData(j, "workStDt") + ds_workTime.getCellData(j, "workStHh");
                    tEndDt = ds_workTime.getCellData(j, "workEndDt") + ds_workTime.getCellData(j, "workEndHh");

                    if (sStDt >= tStDt && sStDt >= tEndDt) {
                        cnt = 1;
                    } else if (sEndDt <= tStDt && sEndDt <= tEndDt) {
                        cnt = 1;
                    }

                    if (cnt == 0) {
                        $c.win.alert((i +1)+ "번째와 " + (j+1) + "번째의 근무시간이 중복되었습니다.");
                        gr_workTime.setFocusedCell(i, "workStDt")
                        return false;
                    }
                }
            }
        }
    }

    let wordTime = ds_workTime.getUnmatchedIndex("rowStatus", "D", true);
    if (wordTime.length <= 1) {
        return true;
    }


    for (let idx = 0; idx < wordTime.length - 1; ++idx) {
        let row = wordTime[idx];
        let nextRow = wordTime[idx + 1];
        let workEndHh = ds_workTime.getCellData(row, "workEndHh");
        let workEndDt = ds_workTime.getCellData(row, "workEndDt");
        if (workEndHh == "2400") {
            sEndDt = $c.date.addDate(workEndDt, 1) + "0000";
        } else {
            sEndDt = workEndDt + workEndHh;
        }
        tStDt = ds_workTime.getCellData(nextRow, "workStDt") + ds_workTime.getCellData(nextRow, "workStHh");
        if (sEndDt != tStDt) {
            $c.win.alert((row+1) + "번째와 " + (nextRow+1) + "번째의 근무시간을 연속적으로 입력해 주십시오.");
            gr_workTime.setFocusedCell(nextRow, "workStDt")
            return false;
        }
    }
    return true;
}

//-------------------------------------------------------------------------
// 근무시간 행추가
//-------------------------------------------------------------------------  
scwin.f_AddRowWorkTime = async function () {

    if (ds_Present.getModifiedIndex().length >= 1) {
        $c.win.alert("휴무입력 완료 후 실적 추가하세요");
        return;
    }

    if(ds_staff.getRowCount() == 0) {
        return;
    }

    let validArray = [
        {id:"workClsCd", name: "근무구분", mandatory: true},
        {id:"workStDt", name: "시작일자", mandatory:true, valid:"date", format: "YYYYMMDD"},
        {id:"workEndDt", name: "시작일자", mandatory:true, valid:"date", format: "YYYYMMDD"},
        {id:"dtlTskCntnCd", name: "업무내용", mandatory: true}
    ];

    ret = await $c.gus.cfValidateGrid(gr_workTime, null, null, validArray, "근무시간");


    if (! ret) {
        return;
    }

    // if (! await $c.gus.cfValidate([gr_workTime])) {
    //     return;
    // }



    if (!scwin.f_checkVacationDate()) {
        return;
    }

    if (ed_branCd.getValue() == "4AA") {
        gr_workTime.setColumnVisible("npGubun", true);
    } else {
        gr_workTime.setColumnVisible("npGubun", false);
    }
    let row = gr_workTime.getFocusedRowIndex();
    if (row < 0) {
        row = null;
    } else {
        ++row;
    }
    row = ds_workTime.insertRow(row);
    ds_workTime.setCellData(row, "staffNo", ds_staff.getCellData(gr_staff.getFocusedRowIndex(), "staffNo"));
    ds_workTime.setCellData(row, "workDt", scwin.ed_wrkDt);

    if (ds_workTime.getTotalRow() > 1) {
        if (ds_workTime.getCellData(row - 1, "workEndHh") == "2400") {
            let newDate = $c.date.addDate(ds_workTime.getCellData(row - 1, "workEndDt"), 1);
            ds_workTime.setCellData(row, "workStDt", newDate);
            ds_workTime.setCellData(row, "workStHh", "0000");
            $c.date.addDate(ds_workTime.getCellData(row - 1, "workEndDt"), 1)
            ds_workTime.setCellData(row, "workEndDt", newDate);
        } else {
            ds_workTime.setCellData(row, "workStDt", ds_workTime.getCellData(row - 1, "workEndDt"));
            ds_workTime.setCellData(row, "workStHh", ds_workTime.getCellData(row - 1, "workEndHh"));
            ds_workTime.setCellData(row, "workEndDt", ds_workTime.getCellData(row - 1, "workEndDt"));
        }
    } else {
        ds_workTime.setCellData(row, "workStDt", scwin.ed_wrkDt);
        ds_workTime.setCellData(row, "workEndDt", scwin.ed_wrkDt);
    }
    gr_workTime.setFocusedCell(i, "workClsCd");
}

scwin.f_CancleRow = function() {
    let focus = gr_workTime.getFocusedRowIndex();

    if(ds_workTime.getRowStatus(focus) == "C") {
        ds_workTime.removeRow(focus);
    } else {
        ds_workTime.undoRow(focus);
    }
}

