scwin.gr_staff_onClick = async function (rowIndex, columnIndex, colid) {
    scwin.colMoveCheck = 0;
    let bModify = false;  //변경된 사항
    let resultCheckCnt = 0;  //실적이 있는것을 첵크했는지
