//-------------------------------------------------------------------------
scwin.btn_deleteRow_onclick = function (e) {
    let row = gr_vacation.getFocusedRowIndex();
    if (row >= 0) {
        if (ds_Present.getRowStatus(row) === "C") {
            ds_Present.removeRow(row);
        } else {
            ds_Present.deleteRow(row);
            gr_vacation.setFocusedCell(row, 0);
        }
    }


    scwin.updateTotalRows2();
};

//-------------------------------------------------------------------------
// 근무시간 그리드 Clear 클릭시
//-------------------------------------------------------------------------
scwin.btn_Clear_onClick = async function (e) {
    let bModify = false;
    for (i = 0; i < ds_workTime.getTotalRow(); i++) {
        if (ds_workTime.getRowStatus(i) != "R") {
            bModify = true;
            break;
        }
    }

    if (!bModify) {
        for (i = 0; i < ds_Present.getTotalRow(); i++) {
            if (ds_Present.getRowStatus(i) != "R") {
                bModify = true;
                break;
            }
        }
    }

    //변경된 사항이 있으면
    if (bModify) {
        if (await $c.win.confirm(MSG_CM_CRM_005)) {
            gr_staff.checkAll("checkBox", "F");
            ds_workTime.removeAll();
        }
        return;
    }

    gr_staff.checkAll("checkBox", "F");

    ds_workTime.removeAll();
    ds_staff.undoAll();
    scwin.cmdKnd = "";
};

//-------------------------------------------------------------------------
// 근무시간 근무구분 콤보 변경에 따른 사용 , 팝업 분기 (밑에 작업지시번호 팝업페이지 작업 안되어있음, 추후 연결)
//-------------------------------------------------------------------------
scwin.gr_workTime_AfterEdit = async function (rowIndex, columnIndex, value) {
    let cnt = 0;
    let colid = gr_workTime.getColumnID(columnIndex);

    if (colid == "workClsCd") {
        if (value == "N") {
            for (i = 0; i < ds_workTime.getTotalRow(); i++) {
                if (ds_workTime.getRowStatus(rowIndex) != "D") {
                    if (i != rowIndex) {
                        if (ds_workTime.getCellData(i, "workClsCd") == "N") {
                            cnt = cnt + 1;
                        }
                    }
                }
            }

            if (cnt >= 1) {
                await $c.win.alert("업무간휴무는한건만 입력하실 수 있습니다.");
                ds_workTime.setCellData(rowIndex, "workClsCd", "");

                return;
            }
        }

        ds_workTime.setCellData(rowIndex, "dtlTskCntnCd", "");
        ds_workTime.setCellData(rowIndex, "wrkIndictNo", "");
        ds_workTime.setCellData(rowIndex, "cvsslNmWrkPlNm", "");
        ds_workTime.setCellData(rowIndex, "shiftClsCd", "");
        ds_workTime.setCellData(rowIndex, "wrkStpCd", "");

        if (value == "A") {   //배치

            gr_workTime.setHeaderColor("column15", "red");  // 작업지시번호     
            gr_workTime.setHeaderColor("column9", "red");  // 작업지시번호    
            gr_workTime.setColumnReadOnly("shiftClsCd", true)
            gr_workTime.setColumnReadOnly("wrkIndictNo", true)
            gr_workTime.setColumnReadOnly("wrkStpCd", true)
            // gr_workTime.setCellReadOnly(rowIndex, "wrkIndictNo", false);	       
            // gr_workTime.setCellReadOnly(rowIndex, "wrkStpCd", false);	       
            // gr_workTime.setCellReadOnly(rowIndex, "shiftClsCd", true);
            gr_workTime.setCellReadOnly(rowIndex, "cond1", false);
            gr_workTime.setCellReadOnly(rowIndex, "cond2", false);
            gr_workTime.setCellReadOnly(rowIndex, "cond3", false);
            gr_workTime.setCellReadOnly(rowIndex, "cond4", false);
            gr_workTime.setCellReadOnly(rowIndex, "cond5", false);
            gr_workTime.setCellReadOnly(rowIndex, "cond6", false);
            gr_workTime.setCellReadOnly(rowIndex, "cond7", false);
            gr_workTime.setCellReadOnly(rowIndex, "cond8", false);
            // gr_workTime.setCellReadOnly(rowIndex, "emgcOdrYn", false);
            // gr_workTime.setCellReadOnly(rowIndex, "commWrkScYn", false);
            // gr_workTime.setCellReadOnly(rowIndex, "commWrkScStd", false);
            // gr_workTime.setCellReadOnly(rowIndex, "rainScYn", false);
            // gr_workTime.setCellReadOnly(rowIndex, "rainScStd", false);
            // gr_workTime.setCellReadOnly(rowIndex, "snowScYn", false);
            // gr_workTime.setCellReadOnly(rowIndex, "snowScStd", false);
            // gr_workTime.setCellReadOnly(rowIndex, "gangWrkYn", false);
            // gr_workTime.setCellReadOnly(rowIndex, "gangWrkStd", false);
            // gr_workTime.setCellReadOnly(rowIndex, "odrReqYn", false);
            // gr_workTime.setCellReadOnly(rowIndex, "odrReqStd", false);
            // gr_workTime.setCellReadOnly(rowIndex, "extendWrkScYn", false);
            // gr_workTime.setCellReadOnly(rowIndex, "extendWrkScStd", false);
            // gr_workTime.setCellReadOnly(rowIndex, "holiWrkScYn", false);
            // gr_workTime.setCellReadOnly(rowIndex, "holiWrkScStd", false);
        } else if (value == "U") {
            // gr_workTime.setCellReadOnly("wrkIndictNo", true);	       
            // gr_workTime.setCellReadOnly("wrkStpCd", true);	  
            // gr_workTime.setCellReadOnly("shiftClsCd", true);	

            gr_workTime.setColumnReadOnly("shiftClsCd", true)
            gr_workTime.setColumnReadOnly("wrkIndictNo", true)
            gr_workTime.setColumnReadOnly("wrkStpCd", true)
            gr_workTime.setHeaderColor("column15", "black");  // 작업지시번호     
            gr_workTime.setHeaderColor("column9", "black");  // 작업지시번호     
        } else if (value == "O") {
            gr_workTime.setHeaderColor("column21", "red");  // 작업지시번호     
            gr_workTime.setHeaderColor("column19", "red");  // 작업지시번호     
            gr_workTime.setHeaderColor("column3", "red");  // 작업지시번호    
            gr_vacation.setColumnReadOnly("vacaRsnCd", false);
            gr_vacation.setColumnReadOnly("vacaStDt", false);
            gr_vacation.setColumnReadOnly("vacaEndDt", false);
        }
        scwin.setTskCntnFilter(value);
        ds_workTime.setCellData(rowIndex, "dtlTskCntnCd", ds_tskCntn.getCellData(0, "cd"));
    } else if (colid == "wrkIndictNo") { // 작업 지시 번호 팝업
        if(value == "") {
            return;
        }

        if(value == scwin.olddata) {
            return;
        }

        let rowObj = ds_workTime.getRowJSON(rowIndex);
        arrParm = [
            new Array("하역작업지시번호 검색", "작업지시구분", "작업일자", 'retrieveWrkIndictNoList', "F", 5, "F", "T", "T"),
            new Array(rowObj.wrkIndictKndCd, ica_qryWrkDt.getValue().trim(), rowObj.wrkIndictNo.trim(), null)
        ];

        // 팝업 옵션 설정
        let options = {
            id: "wrkIndictPop",
            type: "browserPopup",
            popupName: "하역작업지시번호 검색",
            width: 950,
            height: 530
        };

        //상세화면 호출
        let rtn = await $c.win.openPopup("/ui/ds/op/wrkplan/stvwrkplan/op_204_02_08p.xml", options, arrParm);
        if (rtn != null) {
            ds_workTime.setCellData(rowIndex, "wrkIndictNo", rtn[0]);
            ds_workTime.setCellData(rowIndex, "wrkIndictKndCd", rtn[1]);
            ds_workTime.setCellData(rowIndex, "cvsslNmWrkPlNm", rtn[3]);
            ds_workTime.setCellData(rowIndex, "shiftClsCd", rtn[5]);
            scwin.v_workClsCd = rtn[1];

            //20.09.25 RPA 실적입력용 추가
            //인천 북항일 경우 북항여부 조회 후 체크
            if (ed_branCd.getValue() == "4AA") {
                dma_condition2.set("stvWrkIndictNo", rtn[0]);
                ds_npGubun.setJSON([]);
                await $c.sbm.execute(sbm_checkNorthPort);
                // ds_workTime.setCellData(rowIndex, "npGubun", ds_npGubun.getCellData(0, "chk"));
                // ds_workTime.setCellData(rowIndex, "wrkStpCd", "004");
            }

        } else {
            ds_workTime.setCellData(rowIndex, "wrkIndictNo", "");
            ds_workTime.setCellData(rowIndex, "wrkIndictKndCd", "");
            ds_workTime.setCellData(rowIndex, "cvsslNmWrkPlNm", "");
            ds_workTime.setCellData(rowIndex, "shiftClsCd", "");
            ds_workTime.setCellData(rowIndex, "wrkStpCd", "");
        }
    }
}

