scwin.udc_bran_callBackFunc = function (ret) {
    $c.gus.cfSetReturnValue(ret, ed_branCd, ed_branNm);
    if (ed_branCd.getValue() == "4AA") {
        gr_workTime.setColumnVisible("npGubun", true);
    } else {
        gr_workTime.setColumnVisible("npGubun", false);
    }
}

//-------------------------------------------------------------------------
// 근무시간 그리드 셀 클릭
//-------------------------------------------------------------------------
scwin.gr_workTime_onCellClick = function (rowIndex, columnIndex, columnId) {
    scwin.selectedRow = rowIndex;
    scwin.selectedGrid = "gr_workTime";
    scwin.selectedCol = columnId;
    let workClsCd = ds_workTime.getCellData(rowIndex, "workClsCd");
    scwin.setTskCntnFilter(workClsCd);

    if (ds_workTime.getRowCount() > 0) {
        scwin.v_workClsCd = ds_workTime.getCellData(rowIndex, "wrkIndictKndCd");
        scwin.ds_wkrStp_filter();
    }

    if (workClsCd == "A") {   //배치
        gr_workTime.setHeaderColor("column15", "red");  // 작업지시번호     
        gr_workTime.setHeaderColor("column9", "red");  // 작업지시번호   

        gr_workTime.setColumnReadOnly("wrkStpCd", true);
        gr_workTime.setColumnReadOnly("shiftClsCd", true);
        gr_workTime.setColumnReadOnly("wrkIndictNo", false);
        gr_workTime.setColumnReadOnly("wrkStpCd", false);
        // gr_workTime.setColumnReadOnly("cond1", false);
        // gr_workTime.setColumnReadOnly("cond2", false);
        // gr_workTime.setColumnReadOnly("cond3", false);
        // gr_workTime.setColumnReadOnly("cond4", false);
        // gr_workTime.setColumnReadOnly("cond5", false);
        // gr_workTime.setColumnReadOnly("cond6", false);
        // gr_workTime.setColumnReadOnly("cond7", false);
        // gr_workTime.setColumnReadOnly("cond8", false);
        // gr_workTime.setColumnReadOnly("emgcOdrYn", false);
        // gr_workTime.setColumnReadOnly("commWrkScYn", false);
        // gr_workTime.setColumnReadOnly("commWrkScStd", false);
        // gr_workTime.setColumnReadOnly("rainScYn", false);
        // gr_workTime.setColumnReadOnly("rainScStd", false);
        // gr_workTime.setColumnReadOnly("snowScYn", false);
        // gr_workTime.setColumnReadOnly("snowScStd", false);
        // gr_workTime.setColumnReadOnly("gangWrkYn", false);
        // gr_workTime.setColumnReadOnly("gangWrkStd", false);
        // gr_workTime.setColumnReadOnly("odrReqYn", false);
        // gr_workTime.setColumnReadOnly("odrReqStd", false);
        // gr_workTime.setColumnReadOnly("extendWrkScYn", false);
        // gr_workTime.setColumnReadOnly("extendWrkScStd", false);
        // gr_workTime.setColumnReadOnly("holiWrkScYn", false);
        // gr_workTime.setColumnReadOnly("holiWrkScStd", false);
    } else {
        gr_workTime.setColumnReadOnly("wrkIndictNo", true);
        gr_workTime.setColumnReadOnly("wrkStpCd", true);
        gr_workTime.setColumnReadOnly("shiftClsCd", true);
        gr_workTime.setHeaderColor("column15", "black");  // 작업지시번호     
        gr_workTime.setHeaderColor("column9", "black");  // 작업지시번호   
    }

    if (rowIndex >= 0) {
        if (columnId == "emgcOdrYn" || columnId == "commWrkScYn" || columnId == "rainScYn" || columnId == "snowScYn" || columnId == "gangWrkYn"
            || columnId == "odrReqYn" || columnId == "extendWrkScYn" || columnId == "holiWrkScYn") {
            let vChkVal = ds_workTime.getCellData(rowIndex, columnId);

            if (vChkVal == "0") {
                ds_workTime.setCellData(rowIndex, columnId, "1");

            } else if (vChkVal == "1") {
                ds_workTime.setCellData(rowIndex, columnId, "0");

            }
            gr_workTime.setFocusedCell(rowIndex, "shift");
        } else if (columnId == "wrkStpCd") {
            scwin.ds_wkrStp_filter();
        }
    } 

};

//-------------------------------------------------------------------------
// 저장 완료시
//-------------------------------------------------------------------------
scwin.sbm_saveWork_submitDone = async function (e) {
    try{
        if (e.responseJSON.resultDataSet[0].Code < 0) {
            // await $c.win.alert(e.responseJSON.resultDataSet[1].Msg);
            return; //onFail
        }

        scwin.cmdKnd = "save";
        scwin.debugCheck++

        await $c.win.alert(MSG_CM_INF_001);	// 성공적으로 저장하였습니다.


        ds_workTime.setJSON([]);

        dma_searchStaff.set("branCd", ed_branCd.getValue()) //점소
        dma_searchStaff.set("occptypeCd", acb_occptypeCd.getValue()); //직종
        dma_searchStaff.set("dtlOccptypeCd", acb_dtlOccptypeCd.getValue()); //상세직종
        dma_searchStaff.set("staffNo", ed_staffNo.getValue()); //인원
        dma_searchStaff.set("wrkDt", ica_qryWrkDt.getValue()); //일자

        scwin.ed_wrkDt = ica_qryWrkDt.getValue();


        // await scwin.btn_retrieve_onClick();

        let k = 0;
        for (let staffNo of scwin.checkStaffArray) {
            let matched = ds_staff.getMatchedIndex("staffNo", staffNo, true);
            if (matched.length >= 1) {
                k = matched;
                ds_staff.setCellData(k, "checkBox", "T");
                break;
            }
        }

        // ds_staff.setJSON([]);
        await scwin.f_retrieveDetail(k);
        // scwin.gr_staff_onClick(k , "", "");


        await $c.sbm.execute(sbm_searchStaff);

        // scwin.gr_staff_onClick(k, "", "");
    } catch (e) {
       console.log("sbm_saveAcctRecvBdebt_submitdone : " + e);
    }



};

scwin.sbm_saveVacation_submitdone = async function (e) {
    try{
        if (e.responseJSON.resultDataSet[0].Code < 0) {
            await $c.win.alert(e.responseJSON.resultDataSet[1].Msg);
            return; //onFail
        }
        await $c.sbm.execute(sbm_searchVacation);
    } catch (e) {
       console.log("sbm_saveAcctRecvBdebt_submitdone : " + e);
    }

};

//-------------------------------------------------------------------------
// 기능직 휴무 그리드 데이터셋 로드 완료시
//-------------------------------------------------------------------------
scwin.updateGrVacationCellInputType = function () {
    let idx = 0;
    let rowCnt = Math.min($c.num.parseInt(spa_totalRows2.getValue(), 0), ds_Present.getTotalRow());
    for (; idx < rowCnt; ++idx) {
        gr_vacation.setCellInputType(idx, "vacaStDt", { "inputType": "text" });
    }
    rowCnt = ds_Present.getTotalRow();
    for (; idx < rowCnt; ++idx) {
        gr_vacation.setCellInputType(idx, "vacaStDt", { "inputType": "calendar", options: {} });
    }



};

scwin.sbm_searchVacation_submitdone = function (e) {
    scwin.updateTotalRows2();
};

scwin.updateTotalRows2 = function () {
    spa_totalRows2.setValue(ds_Present.getTotalRow());
    scwin.updateGrVacationCellInputType();
};

//-------------------------------------------------------------------------
// 휴무 인원 그리드 팝업 셀
//-------------------------------------------------------------------------
scwin.gr_Vacation_AfterEdit = async function (rowIndex, columnIndex, value) {
    let colid = gr_vacation.getColumnID(columnIndex);
    ds_Present.setCellData(rowIndex, colid, value.toUpperCase());
};

scwin.gr_vacation_oneditend = function (row, col, value) {
    let colid = gr_vacation.getColumnID(col);
    if (ds_Present.getCellData(row, col) == value) {
        return;
    }
    if (colid == "staffNo") {
        ds_Present.setCellData(row, "staffNm", "");	//사원명
        ds_Present.setCellData(row, "lodeptNm", "");	//물류부서
        ds_Present.setCellData(row, "occptypeNm", "");	//직종		    
        ds_Present.setCellData(row, "dtlOccptypeNm", "");	//상세직종
        scwin.f_openGridStaffNoPopUp(row, value, '', 'F');
    }
};

scwin.gr_Vacation_onpopup = function (row, colid, value) {
    if ($c.num.parseInt(spa_totalRows2.getValue(), 0) <= row) {
        switch (colid) {
            case "staffNo":
                scwin.f_openGridStaffNoPopUp(row, ds_Present.getCellData(row, "staffNo"), '', 'F');
                break;
        }
    }
};

